Same as the above in {{arma3}} but without second [[hint]] displayed:<br>[[File:HintC.jpg|400px|right]]
<sqf>
hintC "Press W to move forward";
hintC_EH = findDisplay 57 displayAddEventHandler ["Unload", {
	_this spawn {
		_this select 0 displayRemoveEventHandler ["Unload", hintC_EH];
		hintSilent "";
	};
}];
</sqf>

Same as the above in {{arma3}} but without second [[hint]] displayed:<br>[[File:HintC_array.jpg|400px|right]]
<sqf>
"Instructions" hintC [
	"Press W to move forward.",
	"Press S to move backwards.",
	"Use the mouse to turn right or left.",
	"Press V for weapon sights."
];
hintC_EH = findDisplay 72 displayAddEventHandler ["Unload", {
	_this spawn {
		_this select 0 displayRemoveEventHandler ["Unload", hintC_EH];
		hintSilent "";
	};
}];
</sqf>
